const body = $input.first().json.body || {};
const calendarId = body.calendar_id || (typeof process !== 'undefined' && process.env?.CLIENT_CALENDAR_ID) || 'primary';

// date_debut et date_fin sont des YYYY-MM-DD calculés par le LLM
const dateDebut = body.date_debut || new Date().toISOString().slice(0, 10);
const dateFin   = body.date_fin   || dateDebut;

// Minuit Paris = UTC-2 (été) → on ajoute T00:00:00+02:00 / T23:59:59+02:00
const timeMin = dateDebut + 'T00:00:00+02:00';
const timeMax = dateFin   + 'T23:59:59+02:00';

return [{ json: { dateDebut, dateFin, calendarId, timeMin, timeMax } }];

const items = $input.all();
const cfg = $('Calcul plage horaire').first().json;
const timeMin = new Date(cfg.timeMin);
const timeMax = new Date(cfg.timeMax);

// Filtre JS : garde uniquement les events dans la plage (Bug A — filtre n8n parfois ignoré)
const events = items
  .map(i => i.json)
  .filter(e => {
    if (!e.id) return false;
    const start = new Date(e.start?.dateTime || e.start?.date);
    return start >= timeMin && start <= timeMax;
  });

return [{ json: { ok: true, date_debut: cfg.dateDebut, date_fin: cfg.dateFin, events, count: events.length, fetched_at: new Date().toISOString() } }];
